     1→import { api } from "./api.js";
     2→
     3→// ── State ──────────────────────────────────────────────
     4→let currentMember = null;
     5→
     6→// ── Helpers ────────────────────────────────────────────
     7→function statusBadge(status) {
     8→    return `<span class="badge badge-${status}">${status.replace(/_/g, " ")}</span>`;
     9→}
    10→
    11→function showError(el, msg) {
    12→    el.innerHTML = `<div class="alert alert-error">${msg}</div>`;
    13→}
    14→
    15→function fmt(val) {
    16→    return val == null ? "—" : `$${parseFloat(val).toFixed(2)}`;
    17→}
    18→
    19→// ── Member lookup ───────────────────────────────────────
    20→const memberInput = document.getElementById("member-input");
    21→const loadBtn     = document.getElementById("load-btn");
    22→const memberCard  = document.getElementById("member-card");
    23→const claimsSection = document.getElementById("claims-section");
    24→const newClaimBtn = document.getElementById("new-claim-btn");
    25→
    26→async function loadMember() {
    27→    const val = memberInput.value.trim();
    28→    if (!val) return;
    29→    memberCard.innerHTML = `<span class="skeleton" style="width:200px;height:14px"></span>`;
    30→    memberCard.classList.remove("hidden");
    31→    claimsSection.classList.add("hidden");
    32→    newClaimBtn.classList.add("hidden");
    33→
    34→    try {
    35→        let member;
    36→        if (val.includes("@")) {
    37→            member = await api.lookupMemberByEmail(val);
    38→        } else {
    39→            member = await api.getMember(val);
    40→        }
    41→        currentMember = member;
    42→        renderMemberCard(member);
    43→        await loadClaims(member.id);
    44→        newClaimBtn.classList.remove("hidden");
    45→    } catch (err) {
    46→        showError(memberCard, err.message);
    47→        currentMember = null;
    48→        claimsSection.classList.add("hidden");
    49→    }
    50→}
    51→
    52→function renderMemberCard(m) {
    53→    memberCard.innerHTML = `
    54→        <div style="display:flex;align-items:center;gap:24px;flex-wrap:wrap">
    55→            <div>
    56→                <div style="font-size:16px;font-weight:700">${m.name}</div>
    57→                <div class="id-mono">${m.id}</div>
    58→            </div>
    59→            <div class="claim-header" style="flex:1;min-width:0">
    60→                <div class="claim-header__item"><label>Email</label><span class="value">${m.email}</span></div>
    61→                <div class="claim-header__item"><label>DOB</label><span class="value">${m.date_of_birth}</span></div>
    62→                ${m.phone ? `<div class="claim-header__item"><label>Phone</label><span class="value">${m.phone}</span></div>` : ""}
    63→            </div>
    64→        </div>`;
    65→}
    66→
    67→loadBtn.addEventListener("click", loadMember);
    68→memberInput.addEventListener("keydown", (e) => { if (e.key === "Enter") loadMember(); });
    69→
    70→// ── Claims table ────────────────────────────────────────
    71→const claimsBody  = document.getElementById("claims-body");
    72→const claimsError = document.getElementById("claims-error");
    73→
    74→async function loadClaims(memberId) {
    75→    claimsSection.classList.remove("hidden");
    76→    claimsError.innerHTML = "";
    77→    claimsBody.innerHTML = `<tr><td colspan="6"><span class="skeleton" style="width:100%;display:block"></span></td></tr>`;
    78→
    79→    try {
    80→        const claims = await api.getMemberClaims(memberId);
    81→        renderClaimsTable(claims);
    82→    } catch (err) {
    83→        claimsBody.innerHTML = "";
    84→        showError(claimsError, err.message);
    85→    }
    86→}
    87→
    88→function renderClaimsTable(claims) {
    89→    if (claims.length === 0) {
    90→        claimsBody.innerHTML = `<tr><td colspan="6"><div class="empty-state">No claims found for this member.</div></td></tr>`;
    91→        return;
    92→    }
    93→    claimsBody.innerHTML = claims.map(c => `
    94→        <tr>
    95→            <td><a href="/claim?id=${c.id}" class="text-mono">${c.id.slice(0, 8)}…</a></td>
    96→            <td>${c.date_of_service}</td>
    97→            <td>${statusBadge(c.status)}</td>
    98→            <td>${c.provider_name}</td>
    99→            <td class="text-right text-mono">${fmt(c.total_billed)}</td>
   100→            <td class="text-right text-mono">${fmt(c.total_plan_pays)}</td>
   101→        </tr>`).join("");
   102→}
   103→
   104→// ── New Claim Modal ─────────────────────────────────────
   105→const modalOverlay   = document.getElementById("modal-overlay");
   106→const modalCloseBtn  = document.getElementById("modal-close");
   107→const claimForm      = document.getElementById("claim-form");
   108→const lineItemsWrap  = document.getElementById("line-items-wrap");
   109→const addLineItemBtn = document.getElementById("add-line-item");
   110→const claimFormError = document.getElementById("claim-form-error");
   111→const submitClaimBtn = document.getElementById("submit-claim-btn");
   112→const providerSelect = document.getElementById("provider-id");
   113→
   114→newClaimBtn.addEventListener("click", openModal);
   115→modalCloseBtn.addEventListener("click", closeModal);
   116→modalOverlay.addEventListener("click", (e) => { if (e.target === modalOverlay) closeModal(); });
   117→
   118→async function openModal() {
   119→    claimFormError.innerHTML = "";
   120→    claimForm.reset();
   121→    renderLineItems();
   122→    modalOverlay.classList.remove("hidden");
   123→
   124→    // Populate provider dropdown
   125→    providerSelect.innerHTML = `<option value="">Loading providers…</option>`;
   126→    try {
   127→        const providers = await api.listProviders();
   128→        if (providers.length === 0) {
   129→            providerSelect.innerHTML = `<option value="">No providers found</option>`;
   130→        } else {
   131→            providerSelect.innerHTML = `<option value="">Select provider…</option>` +
   132→                providers.map(p => `<option value="${p.id}">${p.name} (${p.npi})</option>`).join("");
   133→        }
   134→    } catch {
   135→        providerSelect.innerHTML = `<option value="">Failed to load providers</option>`;
   136→    }
   137→}
   138→
   139→function closeModal() {
   140→    modalOverlay.classList.add("hidden");
   141→}
   142→
   143→// ── Line items ──────────────────────────────────────────
   144→let lineItems = [{ cpt_code: "", diagnosis_code: "", billed_amount: "" }];
   145→
   146→function renderLineItems() {
   147→    lineItemsWrap.innerHTML = lineItems.map((item, i) => `
   148→        <div class="line-item-row" data-index="${i}">
   149→            <div class="form-group">
   150→                ${i === 0 ? "<label>CPT Code</label>" : ""}
   151→                <input class="form-control" placeholder="e.g. 99213" value="${item.cpt_code}"
   152→                    oninput="window._liUpdate(${i},'cpt_code',this.value)">
   153→            </div>
   154→            <div class="form-group">
   155→                ${i === 0 ? "<label>Diagnosis Code</label>" : ""}
   156→                <input class="form-control" placeholder="e.g. Z00.00" value="${item.diagnosis_code}"
   157→                    oninput="window._liUpdate(${i},'diagnosis_code',this.value)">
   158→            </div>
   159→            <div class="form-group">
   160→                ${i === 0 ? "<label>Billed Amount</label>" : ""}
   161→                <input class="form-control" placeholder="0.00" type="number" min="0" step="0.01" value="${item.billed_amount}"
   162→                    oninput="window._liUpdate(${i},'billed_amount',this.value)">
   163→            </div>
   164→            <button type="button" class="btn btn-outline btn-sm" onclick="window._liRemove(${i})"
   165→                ${lineItems.length === 1 ? "disabled" : ""}>✕</button>
   166→        </div>`).join("");
   167→}
   168→
   169→window._liUpdate = (i, field, val) => { lineItems[i][field] = val; };
   170→window._liRemove = (i) => { if (lineItems.length > 1) { lineItems.splice(i, 1); renderLineItems(); } };
   171→addLineItemBtn.addEventListener("click", () => {
   172→    lineItems.push({ cpt_code: "", diagnosis_code: "", billed_amount: "" });
   173→    renderLineItems();
   174→});
   175→
   176→// ── Submit claim ────────────────────────────────────────
   177→claimForm.addEventListener("submit", async (e) => {
   178→    e.preventDefault();
   179→    if (!currentMember) return;
   180→
   181→    claimFormError.innerHTML = "";
   182→    submitClaimBtn.disabled = true;
   183→    submitClaimBtn.textContent = "Submitting…";
   184→
   185→    const providerId = providerSelect.value;
   186→    const dateOfService = document.getElementById("date-of-service").value;
   187→
   188→    if (!providerId || !dateOfService) {
   189→        showError(claimFormError, "Provider and date of service are required.");
   190→        submitClaimBtn.disabled = false;
   191→        submitClaimBtn.textContent = "Submit Claim";
   192→        return;
   193→    }
   194→
   195→    const items = lineItems.map(li => ({
   196→        cpt_code: li.cpt_code.trim(),
   197→        diagnosis_code: li.diagnosis_code.trim(),
   198→        billed_amount: parseFloat(li.billed_amount),
   199→    }));
   200→
   201→    if (items.some(li => !li.cpt_code || !li.diagnosis_code || isNaN(li.billed_amount))) {
   202→        showError(claimFormError, "All line items must have CPT code, diagnosis code, and billed amount.");
   203→        submitClaimBtn.disabled = false;
   204→        submitClaimBtn.textContent = "Submit Claim";
   205→        return;
   206→    }
   207→
   208→    try {
   209→        const claim = await api.submitClaim({
   210→            member_id: currentMember.id,
   211→            provider_id: providerId,
   212→            date_of_service: dateOfService,
   213→            line_items: items,
   214→        });
   215→        closeModal();
   216→        lineItems = [{ cpt_code: "", diagnosis_code: "", billed_amount: "" }];
   217→        // Navigate to claim detail
   218→        window.location.href = `/claim?id=${claim.id}`;
   219→    } catch (err) {
   220→        showError(claimFormError, err.message);
   221→        submitClaimBtn.disabled = false;
   222→        submitClaimBtn.textContent = "Submit Claim";
   223→    }
   224→});
