     3→// ── Helpers ─────────────────────────────────────────────
     4→function statusBadge(status) {
     5→    return `<span class="badge badge-${status}">${status.replace(/_/g, " ")}</span>`;
     6→}
     7→
     8→function fmt(val) {
     9→    return val == null ? "—" : `$${parseFloat(val).toFixed(2)}`;
    10→}
    11→
    12→function showError(el, msg) {
    13→    el.innerHTML = `<div class="alert alert-error">${msg}</div>`;
    14→}
    15→
    16→// ── Boot ─────────────────────────────────────────────────
    17→const params  = new URLSearchParams(window.location.search);
    18→const claimId = params.get("id");
    19→const root    = document.getElementById("claim-root");
    20→
    21→if (!claimId) {
    22→    root.innerHTML = `<div class="alert alert-error">No claim ID specified in URL.</div>`;
    23→} else {
    24→    loadClaim();
    25→}
    26→
    27→async function loadClaim() {
    28→    root.innerHTML = `<div class="skeleton" style="height:80px;margin-bottom:16px"></div>
    29→                      <div class="skeleton" style="height:200px"></div>`;
    30→    try {
    31→        const claim = await api.getClaim(claimId);
    32→        renderClaim(claim);
    33→    } catch (err) {
    34→        root.innerHTML = `<div class="alert alert-error">${err.message}</div>`;
    35→    }
    36→}
    37→
    38→// ── Render ───────────────────────────────────────────────
    39→function renderClaim(claim) {
    40→    const activeItems = claim.line_items;
    41→
    42→    const totalPlanPays   = activeItems.reduce((s, li) =>
    43→        s + (li.adjudication_result ? parseFloat(li.adjudication_result.plan_pays) : 0), 0);
    44→    const totalMemberOwes = activeItems.reduce((s, li) =>
    45→        s + (li.adjudication_result ? parseFloat(li.adjudication_result.member_owes) : 0), 0);
    46→
    47→    root.innerHTML = `
    48→        <!-- Header -->
    49→        <div class="card">
    50→            <div class="claim-header">
    51→                <div class="claim-header__item">
    52→                    <label>Claim ID</label>
    53→                    <span class="value id-mono">${claim.id}</span>
    54→                </div>
    55→                <div class="claim-header__item">
    56→                    <label>Status</label>
    57→                    <span class="value">${statusBadge(claim.status)}</span>
    58→                </div>
    59→                <div class="claim-header__item">
    60→                    <label>Review Type</label>
    61→                    <span class="value">${claim.review_type}</span>
    62→                </div>
    63→                <div class="claim-header__item">
    64→                    <label>Date of Service</label>
    65→                    <span class="value">${claim.date_of_service}</span>
    66→                </div>
    67→                <div class="claim-header__item">
    68→                    <label>Member</label>
    69→                    <span class="value">${claim.member.name}</span>
    70→                </div>
    71→                <div class="claim-header__item">
    72→                    <label>Provider</label>
    73→                    <span class="value">${claim.provider.name}</span>
    74→                </div>
    75→                <div class="claim-header__item">
    76→                    <label>Plan</label>
    77→                    <span class="value">${claim.policy.plan_name}</span>
    78→                </div>
    79→                <div class="claim-header__item">
    80→                    <label>Submitted</label>
    81→                    <span class="value">${new Date(claim.submitted_at).toLocaleString()}</span>
    82→                </div>
    83→            </div>
    84→        </div>
    85→
    86→        <!-- Line items -->
    87→        <div class="card">
    88→            <div class="card__title">Line Items</div>
    89→            <div class="table-wrap">
    90→                <table>
    91→                    <thead>
    92→                        <tr>
    93→                            <th>CPT Code</th>
    94→                            <th>Diagnosis</th>
    95→                            <th class="text-right">Billed</th>
    96→                            <th class="text-right">Applied to Ded.</th>
    97→                            <th class="text-right">Plan Pays</th>
    98→                            <th class="text-right">Member Owes</th>
    99→                            <th>Status</th>
   100→                            <th></th>
   101→                        </tr>
   102→                    </thead>
   103→                    <tbody id="line-items-body">
   104→                        ${activeItems.map((li, idx) => renderLineItemRow(li, idx)).join("")}
   105→                        <tr class="table-summary">
   106→                            <td colspan="4" class="text-right">Totals</td>
   107→                            <td class="text-right text-mono">${fmt(totalPlanPays)}</td>
   108→                            <td class="text-right text-mono">${fmt(totalMemberOwes)}</td>
   109→                            <td colspan="2"></td>
   110→                        </tr>
   111→                    </tbody>
   112→                </table>
   113→            </div>
   114→        </div>
   115→
   116→        <!-- Conditional sections -->
   117→        <div id="action-sections"></div>
   118→    `;
   119→
   120→    // Wire up expand buttons
   121→    root.querySelectorAll(".expand-btn").forEach(btn => {
   122→        btn.addEventListener("click", () => {
   123→            const rowId = btn.dataset.target;
   124→            const row   = document.getElementById(rowId);
   125→            if (row) row.classList.toggle("hidden");
   126→        });
   127→    });
   128→
   129→    renderActionSections(claim);
   130→}
   131→
   132→function renderLineItemRow(li, idx) {
   133→    const r    = li.adjudication_result;
   134→    const expl = r ? r.explanation : null;
   135→    const rowId = `expl-${idx}`;
   136→    return `
   137→        <tr>
   138→            <td class="text-mono">${li.cpt_code}</td>
   139→            <td class="text-mono">${li.diagnosis_code}</td>
   140→            <td class="text-right text-mono">${fmt(li.billed_amount)}</td>
   141→            <td class="text-right text-mono">${r ? fmt(r.applied_to_deductible) : "—"}</td>
   142→            <td class="text-right text-mono">${r ? fmt(r.plan_pays) : "—"}</td>
   143→            <td class="text-right text-mono">${r ? fmt(r.member_owes) : "—"}</td>
   144→            <td>${statusBadge(li.adjudication_status)}</td>
   145→            <td>${expl ? `<button class="expand-btn" data-target="${rowId}">details</button>` : ""}</td>
   146→        </tr>
   147→        ${expl ? `<tr id="${rowId}" class="explanation-row hidden">
   148→            <td colspan="8">${expl}</td>
   149→        </tr>` : ""}
   150→    `;
   151→}
   152→
   153→// ── Action sections ──────────────────────────────────────
   154→function renderActionSections(claim) {
   155→    const container = document.getElementById("action-sections");
   156→    const sections  = [];
   157→
   158→    // Payment card (status = paid)
   159→    if (claim.status === "paid" && claim.payment) {
   160→        sections.push(`
   161→            <div class="card">
   162→                <div class="card__title">Payment</div>
   163→                <div class="claim-header">
   164→                    <div class="claim-header__item"><label>Amount</label><span class="value text-mono">${fmt(claim.payment.amount)}</span></div>
   165→                    <div class="claim-header__item"><label>Paid At</label><span class="value">${new Date(claim.payment.paid_at).toLocaleString()}</span></div>
   166→                </div>
   167→            </div>`);
   168→    }
   169→
   170→    // Dispute card (denied or partially_approved, no existing dispute)
   171→    if ((claim.status === "denied" || claim.status === "partially_approved") && !claim.dispute) {
   172→        sections.push(`
   173→            <div class="card" id="dispute-card">
   174→                <div class="card__title">Submit Dispute</div>
   175→                <div class="form-group">
   176→                    <label for="dispute-reason">Reason</label>
   177→                    <textarea id="dispute-reason" class="form-control" rows="3"
   178→                        placeholder="Explain why you are disputing this claim…" style="resize:vertical"></textarea>
   179→                </div>
   180→                <div id="dispute-error"></div>
   181→                <div class="form-actions">
   182→                    <button id="submit-dispute-btn" class="btn btn-primary">Submit Dispute</button>
   183→                </div>
   184→            </div>`);
   185→    }
   186→
   187→    // Show existing dispute
   188→    if (claim.dispute) {
   189→        sections.push(`
   190→            <div class="card">
   191→                <div class="card__title">Dispute</div>
   192→                <div class="claim-header">
   193→                    <div class="claim-header__item"><label>Status</label><span class="value">${statusBadge(claim.dispute.status)}</span></div>
   194→                    <div class="claim-header__item"><label>Submitted</label><span class="value">${new Date(claim.dispute.submitted_at).toLocaleString()}</span></div>
   195→                    ${claim.dispute.resolved_at ? `<div class="claim-header__item"><label>Resolved</label><span class="value">${new Date(claim.dispute.resolved_at).toLocaleString()}</span></div>` : ""}
   196→                </div>
   197→                <div style="margin-top:10px">
   198→                    <div style="font-size:12px;font-weight:600;color:var(--text-muted);margin-bottom:4px">REASON</div>
   199→                    <div>${claim.dispute.reason}</div>
   200→                </div>
   201→                ${claim.dispute.reviewer_note ? `
   202→                <div style="margin-top:10px">
   203→                    <div style="font-size:12px;font-weight:600;color:var(--text-muted);margin-bottom:4px">REVIEWER NOTE</div>
   204→                    <div>${claim.dispute.reviewer_note}</div>
   205→                </div>` : ""}
   206→            </div>`);
   207→    }
   208→
   209→    // Re-adjudication card (under_review + manual)
   210→    if (claim.status === "under_review" && claim.review_type === "manual") {
   211→        sections.push(`
   212→            <div class="card" id="readjudicate-card">
   213→                <div class="card__title">Trigger Re-adjudication</div>
   214→                <div class="form-group">
   215→                    <label for="reviewer-note">Reviewer Note (optional)</label>
   216→                    <textarea id="reviewer-note" class="form-control" rows="3"
   217→                        placeholder="Notes from the reviewer…" style="resize:vertical"></textarea>
   218→                </div>
   219→                <div id="readjudicate-error"></div>
   220→                <div class="form-actions">
   221→                    <button id="readjudicate-btn" class="btn btn-primary">Trigger Re-adjudication</button>
   222→                </div>
   223→            </div>`);
   224→    }
   225→
   226→    // Accept payment button (partially_approved, no dispute)
   227→    if (claim.status === "partially_approved" && !claim.dispute) {
   228→        sections.push(`
   229→            <div class="card" id="accept-card">
   230→                <div class="card__title">Accept Partial Payment</div>
   231→                <p style="margin-bottom:12px;color:var(--text-muted);font-size:13px">
   232→                    Accept the partial payment and mark this claim as paid.
   233→                </p>
   234→                <div id="accept-error"></div>
   235→                <button id="accept-btn" class="btn btn-primary">Accept Payment</button>
   236→            </div>`);
   237→    }
   238→
   239→    container.innerHTML = sections.join("");
   240→
   241→    // Wire dispute submit
   242→    const disputeBtn = document.getElementById("submit-dispute-btn");
   243→    if (disputeBtn) {
   244→        disputeBtn.addEventListener("click", async () => {
   245→            const reason = document.getElementById("dispute-reason").value.trim();
   246→            const errEl  = document.getElementById("dispute-error");
   247→            if (!reason) { showError(errEl, "Reason is required."); return; }
   248→            disputeBtn.disabled = true;
   249→            disputeBtn.textContent = "Submitting…";
   250→            try {
   251→                await api.submitDispute(claim.id, reason);
   252→                loadClaim();
   253→            } catch (err) {
   254→                showError(errEl, err.message);
   255→                disputeBtn.disabled = false;
   256→                disputeBtn.textContent = "Submit Dispute";
   257→            }
   258→        });
   259→    }
   260→
   261→    // Wire re-adjudication
   262→    const readjBtn = document.getElementById("readjudicate-btn");
   263→    if (readjBtn) {
   264→        readjBtn.addEventListener("click", async () => {
   265→            const note  = document.getElementById("reviewer-note").value.trim() || null;
   266→            const errEl = document.getElementById("readjudicate-error");
   267→            readjBtn.disabled = true;
   268→            readjBtn.textContent = "Processing…";
   269→            try {
   270→                await api.adjudicate(claim.id, note);
   271→                loadClaim();
   272→            } catch (err) {
   273→                showError(errEl, err.message);
   274→                readjBtn.disabled = false;
   275→                readjBtn.textContent = "Trigger Re-adjudication";
   276→            }
   277→        });
   278→    }
   279→
   280→    // Wire accept payment
   281→    const acceptBtn = document.getElementById("accept-btn");
   282→    if (acceptBtn) {
   283→        acceptBtn.addEventListener("click", async () => {
   284→            const errEl = document.getElementById("accept-error");
   285→            acceptBtn.disabled = true;
